import React, { useState } from "react";

export default function NewFeed() {
  const [toast, setToast] = useState(null);

  const [comments, setComments] = useState([
    { input: '', list: [] },
    { input: '', list: [] },
    { input: '', list: [] },
  ]);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Nội dung chính */}
      <div className="flex-1 ml-[72px] flex flex-col">
        {/* --- Header đã bị loại bỏ --- */}

        {/* Feed hiển thị bài đăng */}
        <div className="flex flex-col items-center gap-4 mt-[20px] w-full">
          {/* Toast */}
          {toast && (
            <div className="fixed top-[40px] right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
              {toast}
            </div>
          )}

          {/* Danh sách bài post */}
          {[0, 1, 2].map((i) => (
            <div key={i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[5px] gap-6">
              {/* Header bài post */}
              <div className="flex items-center gap-4">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png"
                  className="w-[58px] h-[51px]"
                />
                <div className="flex flex-col">
                  <span className="text-black text-xl">Bạn A</span>
                  <span className="text-black text-base">Đã đăng 5 phút trước</span>
                </div>
              </div>

              {/* Ảnh bài đăng */}
              <img
                src={`https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/${["nwti4bgy", "3cxpt7rg", "d7m3bryx"][i]}_expires_30_days.png`}
                className="rounded-lg w-full"
              />

              {/* Khu vực bình luận */}
              <div className="flex items-center gap-2 mt-2">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png"
                  className="w-[39px] h-[45px] cursor-pointer hover:scale-110 transition-transform"
                  onClick={() => showToast("Bạn đã thả tim ❤️")}
                />
                <input
                  placeholder="Bình luận..."
                  value={comments[i]?.input || ''}
                  onChange={(e) => {
                    const newComments = [...comments];
                    newComments[i].input = e.target.value;
                    setComments(newComments);
                  }}
                  className="flex-1 py-2 px-4 rounded-lg text-black border-0"
                />
                <button
                  className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                  onClick={() => {
                    if (!comments[i]?.input?.trim()) return;
                    const newComments = [...comments];
                    newComments[i].list.push(newComments[i].input);
                    newComments[i].input = '';
                    setComments(newComments);
                  }}
                >
                  Gửi
                </button>
              </div>

              {/* Danh sách bình luận */}
              {comments[i]?.list?.length > 0 && (
                <div className="mt-2 ml-12 flex flex-col gap-1">
                  {comments[i].list.map((cmt, idx) => (
                    <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                      {cmt}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
        `}
      </style>
    </div>
  );
}
